//! Integration test for the `BatonError::from_irods` public API.
//!
//! `tests/connection.rs` and `tests/auth.rs` already exercise the
//! happy-path connection and login flows; this file verifies that the
//! error-name-resolution helper is reachable from outside the crate and
//! links correctly against `rodsErrorName` in the iRODS runtime.

use baton_rs::BatonError;

#[test]
fn from_irods_resolves_known_code() {
    let err = BatonError::from_irods(-813000);
    assert_eq!(err.code, -813000);
    assert_eq!(err.message, "CAT_NO_ROWS_FOUND");
}

#[test]
fn from_irods_with_context_combines_name_and_context() {
    let err = BatonError::from_irods_with_context(-305111, "connection refused");
    assert_eq!(err.code, -305111);
    assert_eq!(err.message, "USER_SOCK_CONNECT_ERR: connection refused");
}
